var spiralMatrix = function(m, n, head) {
    const grid = Array.from({length: m}, () => new Array(n).fill(-1));
    let top = 0, bottom = m - 1, left = 0, right = n - 1;
    let node = head;
    while (node && top <= bottom && left <= right) {
        for (let c = left; node && c <= right; c++) {
            grid[top][c] = node.val;
            node = node.next;
        }
        top++;
        for (let r = top; node && r <= bottom; r++) {
            grid[r][right] = node.val;
            node = node.next;
        }
        right--;
        if (top <= bottom) {
            for (let c = right; node && c >= left; c--) {
                grid[bottom][c] = node.val;
                node = node.next;
            }
            bottom--;
        }
        if (left <= right) {
            for (let r = bottom; node && r >= top; r--) {
                grid[r][left] = node.val;
                node = node.next;
            }
            left++;
        }
    }
    return grid;
};
